import asyncio
from concurrent.futures import ProcessPoolExecutor
import json

_process_pool = ProcessPoolExecutor(max_workers=4)

def _parse_large_payload(raw: bytes) -> dict:
    """Runs in a worker process — safe to block."""
    return json.loads(raw)

async def parse_llm_response(raw: bytes) -> dict:
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(_process_pool, _parse_large_payload, raw)

async def slow_sync_tool(path: str) -> str:
    """Offload a blocking filesystem call to a thread pool."""
    return await asyncio.to_thread(open(path).read)
